import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  static const String _authTokenKey = 'auth_token';
  static const String _userDataKey = 'user_data';

  Future<void> login(String username, String password) async {
    final response = await http.post(Uri.parse('https://api.example.com/login'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({'username': username, 'password': password}));

    if (response.statusCode == 200) {
      final authToken = response.body['auth_token'];
      final userData = response.body['user_data'];

      SharedPreferences prefs = await SharedPreferences.getInstance();
      prefs.setString(_authTokenKey, authToken);
      prefs.setString(_userDataKey, jsonEncode(userData));
    } else {
      throw Exception('Failed to login');
    }
  }

  Future<void> logout() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    prefs.remove(_authTokenKey);
    prefs.remove(_userDataKey);
  }

  Future<bool> isLoggedIn() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getString(_authTokenKey) != null;
  }

  Future<Map<String, dynamic>> getUserData() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    final userDataJson = prefs.getString(_userDataKey);
    if (userDataJson == null) return null;
    return jsonDecode(userDataJson);
  }
}